<template>
    <div style="margin:25px;height:75%">

            <n-space justify="center">
      <n-tag size="large"> 查询支架号 </n-tag>
        <n-select style="width: 100px"
                      filterable
                      v-model:value="supportEnd"
                      size="medium"
                      :options="supportOptions"
                      @update:value="selectSupportEnd"/>
      <n-date-picker v-model:value="range" type="datetimerange" clearable />
      <n-button type="Primary" @click="getSupportRealtimeData">查询</n-button>
      <n-button type="Primary" @click="exportToCSV">导出报表</n-button>
        </n-space>
        <n-data-table style="margin: 20px; height: 100%;" size="large" :columns="columns" :data="data" :pagination="pagination" />
       
    </div>
    </template>

<script setup>
import { NDatePicker } from "naive-ui";
import dayjs from "dayjs";
import { useChartsStore} from "@/store/modules/chartsValue"
import { computed,defineComponent, onMounted, ref, reactive ,h} from "vue";
import { useMessage } from "naive-ui";
import {getSupRealtime,getSupportNum} from "@/api/request";
import Papa from 'papaparse'
const nMessage = useMessage();
//获取时间数据value
let endTime = Date.now();
let startTime = endTime - 24 * 60 * 60 * 1000 * 1;
let range = ref([startTime, endTime]);
let chartsStore = useChartsStore();
const supportEnd = ref(1)
const supportOptions = computed(() => {
  return Array.from({ length: chartsStore.supNum }).map((v, k) => {
    return { label: k + 1 + "架", value: k + 1 };
  });
});

const selectSupportEnd = (va) => {
    supportEnd.value = va;
};

const data = ref([])

const columns = ref([
    {
      title: '序号',
      key: 'xh'
      
    },
    {
      title: '地点',
      key: 'dd'
    },
    {
      title: '设备名称',
      key: 'sbmc'
    },
    {
      title: '在线状态',
      key: 'zxzt',
      render: (row) => {
      return h(
        'span',
        {
          style: {
            color: row.zxzt=="在线"  ? 'green' : 'black'
          }
        },
        row.zxzt
      )
    }
    },
    {
      title: '是否识别到煤机',
      key: 'sfsbdmj',
      render: (row) => {
      return h(
        'span',
        {
          style: {
            color: row.sfsbdmj=="是"  ? 'red' : 'black'
          }
        },
        row.sfsbdmj
      )}
    },
    {
      title: '支架动作',
      key: 'zjdz',
      render: (row) => {
      return h(
        'span',
        {
          style: {
            color: row.zjdz!="静止"  ? 'red' : 'black'
          }
        },
        row.zjdz
      )}
    },
    {
      title: '立柱压力',
      key: 'lzyl'
    },
    {
      title: '煤机位置',
      key: 'mjwz'
    },
    {
      title: '推移行程',
      key: 'tyxc'
    },
    {
      title: '顶板X轴倾角',
      key: 'dingbxzqj'
    },
    {
      title: '顶板Y轴倾角',
      key: 'dingbyzqj'
    },
    {
      title: '底板X轴倾角',
      key: 'dibxzqj'
    },
    {
      title: '底板Y轴倾角',
      key: 'dibyzqj'
    },
    {
      title: '数据更新时间',
      key: 'sjgxsj'
    },
    {
      title: '报警状态',
      key: 'bjzt',

      render: (row) => {
      return h(
        'span',
        {
          style: {
            color: row.bjzt=="报警"  ? 'red' : 'black'
          }
        },
        row.bjzt
      )}

    },
    {
      title: '报警原因',
      key: 'bjyy'
    }
  ])

const pagination = ref({pageSize: 15 })
//获取时间戳，并发送查询http请求
const getSupportRealtimeData = async () => {
  console.log("触发查询");
  let { code, message } = await getSupRealtime({
    start_time: dayjs(range.value[0]).format("YYYY-MM-DD HH:mm:ss"),
    end_time: dayjs(range.value[1]).format("YYYY-MM-DD HH:mm:ss"),
    support: supportEnd.value
  });
  console.log("查询返回",message);
  data.value = []
  for(var i=0;i<message.length;i++){
    message[i].xh = i+1
    message[i].sjgxsj = dayjs(message[i].sjgxsj).format("YYYY-MM-DD HH:mm:ss")
                data.value.push(message[i])
            }
            console.log("查询返回",data.value);
}

const exportToCSV = () => {
      try {
        if (data.value.length==0){
            nMessage.success('请先查询')
            return
        }

        const mainTitle = "支架信息报表\n生成日期：" + new Date().toLocaleDateString() + "\n"
        // 使用 PapaParse 将数据转换为 CSV
        const csv = Papa.unparse(data.value, {
          quotes: true, // 为字符串添加引号
          delimiter: ",", // 分隔符
          header: true // 包含表头
        })
        const fullCSV = mainTitle + csv
        // 创建 Blob 对象
        const blob = new Blob(["\uFEFF" + fullCSV], { type: 'text/csv;charset=utf-8;' })
        
        // 创建下载链接
        const link = document.createElement('a')
        const url = URL.createObjectURL(blob)
        link.href = url
        link.download = '支架信息报表'+ new Date().toLocaleDateString()+'.csv'
        document.body.appendChild(link)
        link.click()
        
        // 清理
        setTimeout(() => {
          document.body.removeChild(link)
          URL.revokeObjectURL(url)
        }, 100)

        nMessage.success('导出成功')
      } catch (error) {
        nMessage.error('导出失败: ' + error.message)
      }
    }




onMounted(async () => {
  let res = await getSupportNum();
  if(res.code == 0){
    chartsStore.transSupNumData( Number(res.message));
  }else{
      nMessage.info("未收到数据！");
  }
});
</script>